import React, { useState } from 'react';
import { Button, Select, DateRangeFilter, addToast } from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatVnd, formatQty, formatDate, formatNumber } from '../../../utils/formatters';
import { exportExcel, monthStartEnd, MONTH_OPTIONS, YEAR_OPTIONS } from '../../../utils/exportExcel';
import styles from '../../../styles/erpReportPage.module.css';

import type { PartnerDto, PurchaseReportRow } from '../../../services/analytics/models';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
const GROUP_OPTIONS = [{ value: 'supplier', label: 'Theo NCC' }, { value: 'material', label: 'Theo mặt hàng' }];
const BaoCaoMuaHangPage: React.FC = () => {
  const [reloadKey, setReloadKey] = useState(0);
  const dispatch = useAppDispatch();
  const { fromDate: iF, toDate: iT } = monthStartEnd();
  const [fromDate, setFromDate] = useState(iF);
  const [toDate, setToDate] = useState(iT);
  const [supplierId, setSupplierId] = useState('');
  const [groupBy, setGroupBy] = useState<'supplier' | 'material'>('supplier');
  const [partners, setPartners] = useState<PartnerDto[]>([]);
  const [rows, setRows] = useState<PurchaseReportRow[]>([]);
  const [loading, setLoading] = useState(false);
  const handleSearch = () => setReloadKey(k => k + 1);
  React.useEffect(() => { let c=false; const t=setTimeout(()=>{ analyticsService.getPartners({ partnerType:'Supplier', pageSize:500 }).then(d=>{if(!c)setPartners(d);}).catch(()=>{}); },0); return ()=>{c=true;clearTimeout(t);}; }, []);
  React.useEffect(() => { let c=false; setLoading(true); const t=setTimeout(()=>{ analyticsService.getPurchaseReport({ fromDate, toDate, supplierId: supplierId||undefined, groupBy }).then(d=>{if(!c)setRows(d);}).catch(e=>{if(!c)dispatch(addToast({message:e?.message??'Lỗi tải báo cáo',type:'error'}));}).finally(()=>{if(!c)setLoading(false);}); },0); return ()=>{c=true;clearTimeout(t);}; }, [fromDate,toDate,supplierId,groupBy,dispatch, reloadKey]);
  const bm = groupBy==='material';
  const tQ=rows.reduce((s,r)=>s+(r.quantity??0),0); const tS=rows.reduce((s,r)=>s+(r.subTotal??0),0); const tV=rows.reduce((s,r)=>s+(r.vatAmount??0),0); const tA=rows.reduce((s,r)=>s+(r.totalAmount??0),0);
  const refresh = () => setReloadKey(k => k + 1);
  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}><div className={styles.titleBlock}><h1 className={styles.title}><i className="fas fa-shopping-cart" /> Báo cáo mua hàng</h1><p className={styles.subtitle}>{rows.length} dòng · {fromDate} → {toDate}</p></div>
        <div className={styles.headerActions}><Button variant="secondary" onClick={()=>exportExcel('/accounting/purchase-report/export-excel',{fromDate,toDate,supplierId:supplierId||undefined,groupBy},`BaoCaoMuaHang-${fromDate}.xlsx`)}><i className="fas fa-file-excel" /> Xuất Excel</Button></div></div>
      <div className={styles.filtersBar} data-testid={`erp-bao-cao-mua-hang-filters`}><DateRangeFilter fromDate={fromDate} toDate={toDate} onChange={(v:DateRangeValue)=>{setFromDate(v.fromDate??'');setToDate(v.toDate??'');}} /><Select value={supplierId} onChange={e=>setSupplierId(e.target.value)} options={[{value:'',label:'Tất cả NCC'},...partners.map(p=>({value:p.id,label:`${p.code} — ${p.name}`}))]} size="small" /><Select value={groupBy} onChange={e=>setGroupBy(e.target.value as 'supplier'|'material')} options={GROUP_OPTIONS} size="small" /><ListSearchRefreshButtons testIdPrefix="erp-bao-cao-mua-hang" onSearch={handleSearch} onRefresh={refresh} showSearch={false} /></div>
      <div className={styles.tableCard}>{loading?<div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>:rows.length===0?<div className={styles.empty}><p>Không có dữ liệu</p></div>:<div className={styles.tableWrapper}><table className={styles.table}><thead><tr>{bm?<><th>Mã hàng</th><th>Tên hàng</th><th>ĐVT</th><th>NCC</th></>:<><th>NCC</th><th>Mặt hàng</th></>}<th className={styles.colRight}>SL</th><th className={styles.colRight}>Giá trị</th><th className={styles.colRight}>VAT</th><th className={styles.colRight}>Tổng</th></tr></thead><tbody>{rows.map((r,i)=>(<tr key={i}>{bm?<><td>{r.materialCode??'—'}</td><td>{r.materialName}</td><td>{r.unit??'—'}</td><td>{r.supplierName}</td></>:<><td>{r.supplierName}</td><td>{r.materialName}</td></>}<td className={styles.colRight}>{formatQty(r.quantity)}</td><td className={styles.colRight}>{formatVnd(r.subTotal)}</td><td className={styles.colRight}>{formatVnd(r.vatAmount)}</td><td className={styles.colRight}>{formatVnd(r.totalAmount)}</td></tr>))}<tr className={styles.rowTotal}><td colSpan={bm?4:2}>Tổng</td><td className={styles.colRight}>{formatQty(tQ)}</td><td className={styles.colRight}>{formatVnd(tS)}</td><td className={styles.colRight}>{formatVnd(tV)}</td><td className={styles.colRight}>{formatVnd(tA)}</td></tr></tbody></table></div>}</div>
    </div>
  );
};
export default BaoCaoMuaHangPage;
